<template><div class="composer"><div class="shortcuts"><button v-for="x in ['相册','小额打款','物流客服','邀请下单']" @click="$emit('action',x)">{{x}}</button></div><div v-if="suggestions.length" class="suggestions"><button v-for="q in suggestions" :key="q.id" @click="replace(q.content)">{{q.content}}</button></div><div v-if="emoji" class="emoji-panel"><button v-for="e in emojis" @click="insert(e)">{{e}}</button></div><div v-if="more" class="composer-tools"><button v-for="x in tools" @click="tool(x[0])"><component :is="x[1]"/><span>{{x[0]}}</span></button></div><form @submit.prevent="send"><button type="button" @click="$emit('openQuick')"><MessageSquare/></button><textarea ref="input" v-model="text" placeholder="输入消息" rows="1" @keydown.enter.exact.prevent="send" @focus="closePanels"/><button type="button" @click="toggleEmoji"><Smile/></button><button v-if="!text.trim()" type="button" :disabled="uploading" @click="toggleMore"><Plus/></button><button v-else class="send">发送</button></form><input ref="camera" hidden type="file" accept="image/*" capture="environment" @change="upload"><input ref="photo" hidden type="file" accept="image/*" @change="upload"><input ref="video" hidden type="file" accept="video/*" @change="upload"></div></template>
<script setup lang="ts">import{ref,watch}from'vue';import{MessageSquare,Smile,Plus,Camera,Image,Mic,ShoppingBag,ClipboardList,Banknote,Video}from'lucide-vue-next';const emit=defineEmits(['send','upload','action','openQuick']);const text=ref(''),input=ref<HTMLTextAreaElement>(),camera=ref<HTMLInputElement>(),photo=ref<HTMLInputElement>(),video=ref<HTMLInputElement>(),emoji=ref(false),more=ref(false),uploading=ref(false),suggestions=ref<any[]>([]),emojis=['😀','😃','😄','😁','😆','😂','😊','😍','😘','😎','😭','😡','👍','👎','🙏','🎉','❤️'],tools:any[]=[['拍照',Camera],['照片',Image],['语音',Mic],['商品',ShoppingBag],['订单',ClipboardList],['打款',Banknote],['视频',Video]];let searchTimer:number|undefined;function send(){if(!text.value.trim())return;emit('send',text.value.trim());text.value=''}function insert(v:string){const el=input.value,p=el?.selectionStart??text.value.length;text.value=text.value.slice(0,p)+v+text.value.slice(p);setTimeout(()=>{el?.focus();el?.setSelectionRange(p+v.length,p+v.length)})}function replace(v:string){text.value=v;suggestions.value=[];setTimeout(()=>input.value?.focus())}function toggleEmoji(){emoji.value=!emoji.value;if(emoji.value)more.value=false}function toggleMore(){more.value=!more.value;if(more.value)emoji.value=false}function closePanels(){emoji.value=false;more.value=false}function tool(x:string){if(x==='拍照')camera.value?.click();else if(x==='照片')photo.value?.click();else if(x==='视频')video.value?.click();else emit('action',x)}async function upload(e:Event){const el=e.target as HTMLInputElement,f=el.files?.[0];if(!f)return;uploading.value=true;emit('upload',f,()=>uploading.value=false);el.value=''}watch(text,v=>{if(v.trim())more.value=false;clearTimeout(searchTimer);if(!v.trim())return void(suggestions.value=[]);searchTimer=window.setTimeout(async()=>{try{const r=await fetch('/api/koshop-seller/quick-replies?keyword='+encodeURIComponent(v.trim()));suggestions.value=((await r.json()).items||[]).slice(0,5)}catch{suggestions.value=[]}},180)});defineExpose({replace})</script>
